import{j as e}from"./index-k5fxc_t7.js";import{I as a}from"./IndustryTemplate-Dojgfa3a.js";const i={slug:"legal",label:"Legal",sub:"Personal Injury · Criminal Defense · Family Law · Estate Planning",heroH1:e.jsxs(e.Fragment,{children:["The Firm That Shows Up First",e.jsx("br",{}),"Wins the Client."]}),heroCopy:"Clients research attorneys before calling. Being first in local search and AI recommendations — combined with instant intake — is the difference between signing and losing.",problemTitle:"The Legal Lead Problem",problemBody:["Legal leads operate on a different clock than any other industry. Someone calling about a DUI arrest, a custody situation, or a personal injury isn't comparison shopping calmly — they're in crisis. They're calling multiple firms. The first attorney who responds professionally and immediately wins the retainer. If that call goes to voicemail, the case walks out the door before the tone finishes.","After-hours intake is where law firms lose the most. Criminal defense, DUI, and family law inquiries are disproportionately after-hours calls — emergencies don't keep business hours. A firm that can capture, qualify, and respond to a 10pm DUI inquiry before competing firms open their doors the next morning has an enormous competitive advantage. Most firms aren't doing this.",'Visibility is equally high-stakes. Practice-area searches — "personal injury lawyer in [city]," "DUI attorney near me," "divorce lawyer [neighborhood]" — are high-intent and high-value. AI search platforms are beginning to influence these queries in the same way Google Maps does. Firms with strong review profiles, authoritative practice-area content, and optimized GBP listings are being recommended. Most firms have none of that infrastructure running.'],quote:"A DUI call at 9pm that hits voicemail is a retainer walking out the door. We were losing cases every single night.",stats:[{value:"100%",label:"of after-hours inquiries captured and responded to"},{value:"Auto",label:"lead qualification by practice area"},{value:"Top 3",label:"Map Pack for practice area keywords"}],systems:[{name:"Voice AI",desc:"Answers every inquiry immediately — 24/7. Captures case details by practice area, qualifies urgency, and schedules consultations directly into your calendar. A DUI call at 10pm gets a professional response before any competing firm is open."},{name:"Content AI",desc:"Creates practice-area pages, FAQ content, and GBP posts that establish your authority in Google search and AI recommendations. Structured specifically for high-intent legal queries in your practice areas."},{name:"Reviews AI",desc:"Automates review requests after case conclusions and positive client interactions. Builds your Google rating and review velocity — the signals that drive Map Pack ranking for competitive practice-area keywords."},{name:"Workflow AI",desc:"Automates intake follow-up sequences for prospects who need time to decide, and keeps your referral network engaged with professional automated outreach."},{name:"Conversation AI",desc:"Captures website inquiries instantly — including after hours — and follows up via SMS until consultation is booked. No case inquiry slips away because nobody was online."},{name:"Funnel AI",desc:"Builds practice-area landing pages that convert paid search and organic traffic into booked consultations — with every lead flowing to your intake system immediately."}],bullets:["Answers every inquiry immediately — phone, web chat, after hours — and captures full case details before anyone on your team lifts a finger","Creates practice-area content and FAQ pages that establish authority in Google search and AI recommendations","Qualifies leads by practice area so your time goes to the cases worth taking","Manages your Google reputation with automated review requests and professional AI-generated responses","Automates intake follow-up sequences for prospects who need time to decide","Builds practice-area landing pages that convert paid search traffic into booked consultations"],boldClose:"You close cases. eighty5labs closes the gap between 'I need a lawyer' and 'I'm hiring you.'",faqTitle:"Questions About eighty5labs for Legal",faqs:[{q:"How do law firms rank in Google Maps for practice-area searches?",a:"Google Maps ranks firms based on relevance to the specific search, distance, and prominence. For practice-area searches like 'personal injury lawyer [city],' your GBP primary category, services listed, and review profile all need to be optimized specifically for that practice area. Firms that maintain regular GBP posts, earn consistent reviews, and respond to every review systematically outrank competitors who treat their profile as static."},{q:"Can AI search platforms generate legal leads?",a:"Yes — and the volume is growing. Prospective clients increasingly ask ChatGPT, Gemini, and Perplexity questions like 'best DUI attorney in [city]' or 'who should I hire for a personal injury case in [neighborhood].' These platforms recommend firms with strong review profiles, authoritative practice-area content, and consistent GBP activity. Firms building this infrastructure now are capturing cases before competing firms are even in the conversation."},{q:"How does after-hours intake actually work with Voice AI?",a:"Your Voice AI agent is configured specifically for your practice areas — it knows which questions to ask for a DUI vs. a divorce vs. a personal injury matter. It captures the caller's name, contact information, case details, and urgency level, and can schedule a consultation directly into your calendar. You receive an SMS summary the moment the call ends. By the time you wake up, the intake is done and the consultation is booked."}],ctaTitle:"Find Out How Many Cases You're Losing After Hours",ctaBody:"Free AI Visibility Audit — we'll show you your Map Pack position, review velocity, and where competing firms are capturing inquiries you're missing.",accentColor:"#F59E0B"};function s(){return e.jsx(a,{data:i})}export{s as default};
